What does this program print?

```cpp
#include <iostream>
struct Log {
    int n;
    Log(int x) : n{x} { std::cout << "on " << n << "\n"; }
    ~Log()             { std::cout << "off " << n << "\n"; }
};
int main() {
    Log a{1};
    {
        Log b{2};
        Log c{3};
    }
    // a destroyed here
}
```

